mapper.select:
/* osstMgmtMapper.selectNonOsstRcpList */ SELECT MJ.CONTRACT_NUM, MJ.SCAN_ID, MJ.ON_OFF_TYPE, MJ.OPEN_AGNT_CD, MD.RES_NO, NVL(MD.REQ_BUY_TYPE, 'UU') AS REQ_BUY_TYPE, NVL(MD.REQ_BUY_TYPE_NM, '유심단독구매') AS REQ_BUY_TYPE_NM, MD.MOVE_COMPANY, MD.MOVE_COMPANY_NM, MD.SALE_PLCY_CD, MD.SALE_PLCY_NM, MD.OPEN_MARKET_REFERER, MD.RECOMMEND_FLAG_CD, MD.RECOMMEND_FLAG_NM, MD.RECOMMEND_INFO, MD.REC_YN, MD.SHOP_CD, MD.SHOP_NM, MD.MINOR_AGENT_NAME, MD.MINOR_AGENT_RELATION, MD.MINOR_AGENT_REL_NM, MD.MINOR_AGENT_TEL, MD.APP_CD, MD.APP_NM, MD.JOIN_PAY_MTHD_CD, MD.JOIN_PAY_MTHD_NM, MD.JOIN_PRICE, MD.USIM_PAY_MTHD_CD, MD.USIM_PAY_MTHD_NM, MD.USIM_PRICE, MD.RENTAL_BASE_AMT, MD.RENTAL_BASE_DC_AMT, MD.RENTAL_MODEL_CP_AMT, MD.REQUEST_KEY, '21' AS REQUEST_STATE_CODE, MD.SHOP_USM_ID, MD.REG_DTTM, MJ.PROD_TYPE, MD.PROD_TYPE_NM, MD.REQ_USIM_NAME, MD.FST_RATE_CD, MD.FST_RATE_NM, MD.LST_RATE_CD, MD.LST_RATE_NM, MD.FST_MODEL_INFO, MD.INST_INFO, MD.SIM_INFO, MD.OTA_DATE, MD.CATCH_CALL, MD.DVC_CHG_CNT, MD.DVC_CHG_INFO, MD.CATCH_CALL_CAN, MD.PROMOTION_CD, MD.REAL_SHOP_NM, MJ.PPPO AS SERVICE_TYPE, '00' AS PSTATE, MJ.SUB_LINK_NAME AS CSTMR_NAME, MD.FST_RATE_CD AS SOC_CODE, MJ.OPEN_AGNT_CD AS CNTPNT_SHOP_ID, MD.OPEN_AGNT_CD AS AGENT_CODE, SUBSTR(CRYPTO_AES256.DEC_AES(MJ.USER_SSN),0,6) AS CSTMR_NATIVE_RRN1, SUBSTR(CRYPTO_AES256.DEC_AES(MJ.USER_SSN),7) AS CSTMR_NATIVE_RRN2, CASE WHEN LENGTH(MJ.SUBSCRIBER_NO) = 10 OR LENGTH(MJ.SUBSCRIBER_NO) = 11 THEN SUBSTR(MJ.SUBSCRIBER_NO, 0, 3) END CSTMR_TEL_FN, CASE WHEN LENGTH(MJ.SUBSCRIBER_NO) = 10 THEN SUBSTR(MJ.SUBSCRIBER_NO, 4, 3) WHEN LENGTH(MJ.SUBSCRIBER_NO) = 11 THEN SUBSTR(MJ.SUBSCRIBER_NO, 4, 4) END CSTMR_TEL_MN, CASE WHEN LENGTH(MJ.SUBSCRIBER_NO) = 10 OR LENGTH(MJ.SUBSCRIBER_NO) = 11 THEN SUBSTR(MJ.SUBSCRIBER_NO, -4) END CSTMR_TEL_RN, MJ.ICC_ID AS REQ_USIM_SN, '12,29,30,31' AS ADDITION_KEY, '발신번호표시,스팸차단서비스,정보제공사업자번호차단,통합사서함' AS ADDITION_NAME, '0' AS ADDITION_PRICE, 'N' AS USIM_PRICE_TYPE, 'P' AS JOIN_PRICE_TYPE, MO.OSST_ORDER_SEQ, MO.TR_TIME AS REQ_IN_DAY, /* 개통요청일시 */ MO.NICE_CERT_KEY, /* CI값 */ DECODE(MO.ODER_TYPE_CD,'NAC','NAC3','MNP','MNP3','') AS OPER_TYPE, /* 가입유형 신규개통 NAC, 무선번호이동 MNP */ DECODE(MO.ODER_TYPE_CD,'NAC','신규개통','MNP','번호이동','') AS OPER_TYPE_NM, DECODE(MO.CUST_TYPE,'REGID','01','DRIVE','02','HANDI','03','FORGN','06','MERIT','04',MO.CUST_TYPE) AS SELF_CERT_TYPE, /* 본인인증방식(RCP2006) 주민등록증:REGID, 운전면허증:DRIVE 장애인등록증:HANDI 외국인등록증:FORGN 국가유공자증:MERIT */ DECODE(MO.MYSL_ATHN_TYPE_CD,'01','C','02','A','03','T',MO.MYSL_ATHN_TYPE_CD) AS ONLINE_AUTH_TYPE, /* 인증유형(RCP2001) 신용카드 01, PASS 02, toss인증서 03 */ MO.EML_ADRS_NM AS CSTMR_EMAIL, /* 이메일주소*/ DECODE(MO.WATCH_TYPE_CD, NULL, MO.RQSSHT_PPRFRM_CD, MO.MOTLI_RQSSHT_PPRFRM_CD) AS CSTMR_BILL_SEND_CODE, /* 명세서유형(RCP2008) 우편 LX, 이메일 CB, 모바일MMS MB */ MO.BCHNG_NP_COMM_CMPN_CD AS MOVE_COMPANY, /* 변경전번호이동사업자코드(NSC) */ MO.ATHN_ITEM_CD AS MOVE_AUTH_TYPE, /* 번호이동인증항목코드(RCP2011) */ MO.ATHN_SBST AS MOVE_AUTH_NUMBER, /* 번호이동 인증번호 4자리*/ DECODE(MO.WATCH_TYPE_CD, NULL, MO.BLPYM_MTHD_CD, '0') AS REQ_PAY_TYPE, /* 납부방법코드(RCP2015) */ SUBSTR(MO.CRDT_CARD_EXPR_DATE,1,4) AS REQ_CARD_YY, /* 신용카드 만료일자*/ SUBSTR(MO.CRDT_CARD_EXPR_DATE,5,2) AS REQ_CARD_MM, /* 신용카드 만료일자*/ (SELECT EXPNSN_STR_VAL1 FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID = 'CRDOSST' AND DTL_CD = MO.CRDT_CARD_KIND_CD) REQ_CARD_COMPANY, /* 신용카드 종류(CRDOSST)*/ CASE WHEN SUBSTR(MO.BANK_CD, 1, 1) = '0' THEN SUBSTR(MO.BANK_CD, 2) ELSE MO.BANK_CD END REQ_BANK, /* 은행코드(BNK)*/ DECODE(MO.BLPYM_MTHD_CD,'D',MO.BLPYM_MTHD_IDNT_NO,'') AS REQ_ACCOUNT_NUMBER, /* 계좌번호*/ DECODE(MO.BLPYM_MTHD_CD,'C',MO.BLPYM_MTHD_IDNT_NO,'') AS REQ_CARD_NO, /* 카드번호*/ MD.CSTMR_TYPE, /* 고객구분 - 내국인,외국인,미성년자 */ DECODE(MO.SIM_DIV_CD, 'E', '09', '02') AS USIM_KINDS_CD, /* SIM구분코드(U/E) */ MO.BILL_ACC_ID AS PRNTS_BILL_NO, /* 청구계정ID */ MO.MOTLI_SVC_NO AS PRNTS_CTN, /* 모회선 전화번호 */ (SELECT CASE WHEN JEHU_PROD_TYPE IS NOT NULL THEN 'Y' ELSE 'N' END FROM MSP_RATE_MST WHERE RATE_CD = MD.FST_RATE_CD) AS CLAUSE_JEHU_FLAG, /* 요금제애 제휴처 제공 동의 */ (SELECT JEHU_PROD_TYPE FROM MSP_RATE_MST WHERE RATE_CD = MD.FST_RATE_CD) AS JEHU_PROD_TYPE, /* 요금제애 따른 제휴처 */ NVL((SELECT 'Y' FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID = 'PartnerTerm' AND DTL_CD = MD.OPEN_AGNT_CD),'N') AS CLAUSE_PARTNER_OFFER_FLAG /* 제휴사 제공 동의 */ FROM MSP_JUO_SUB_INFO MJ, MSP_REQUEST_DTL MD, MDS_OSST_ORDER MO WHERE 1 = 1 AND MJ.CONTRACT_NUM = MD.CONTRACT_NUM AND MJ.SUBSCRIBER_NO = MO.REQ_TEL_NO AND MJ.ON_OFF_TYPE = #{jobCd} AND MJ.LST_COM_ACTV_DATE >= TO_CHAR(SYSDATE-7, 'YYYYMMDD') AND MO.NICE_CERT_KEY IS NOT NULL AND MO.STATUS = '09' /* 진행상태 완료 */ AND MO.RCP_CR_YN = 'N' AND MD.REQUEST_KEY IS NULL /* 2023-09-12 신청서 미생성된 고객정보만 추출 */ AND SUBSTR(MO.TR_TIME, 1, 8) >= TO_CHAR(SYSDATE-7, 'YYYYMMDD')
AND MO.CHANNEL_CD = 'KMV' /*TOS:토스, KMV:대고객통합채널*/
AND MO.CHANNEL_CD = 'TOS' /*TOS:토스, KMV:대고객통합채널*/

/* osstMgmtMapper.setMcpRequestDlvryLinkus */ 
SELECT SQ_RCP_REQUEST_STATE_01.NEXTVAL@dl_mcp requestStateKey 
  FROM DUAL

mapper.delete:
/* osstMgmtMapper.deleteRcpAddition */
DELETE FROM MCP_REQUEST_ADDITION@DL_MCP
WHERE REQUEST_KEY = #{requestKey}

/* osstMgmtMapper.deleteMspAddition */
DELETE FROM MSP_REQUEST_ADDITION
WHERE REQUEST_KEY = #{requestKey}

mapper.insert:
/* osstMgmtMapper.insertMspAddition */
INSERT INTO MSP_REQUEST_ADDITION 
( 
	REQUEST_KEY, ADDITION_KEY, ADDITION_NAME, RANTAL 
)
SELECT
	REQUEST_KEY, ADDITION_KEY, ADDITION_NAME, RANTAL
FROM MCP_REQUEST_ADDITION@DL_MCP A
WHERE REQUEST_KEY = #{requestKey}
AND NOT EXISTS (SELECT 1 FROM MSP_REQUEST_ADDITION WHERE REQUEST_KEY = A.REQUEST_KEY)

mapper.update:
/* osstMgmtMapper.updateAppFormXmlYn */
UPDATE  MCP_REQUEST@DL_MCP
SET     APP_FORM_XML_YN = 'Y',
		RVISN_ID = #{userId},
		RVISN_DTTM = SYSDATE 
WHERE   REQUEST_KEY = #{requestKey}

/* osstMgmtMapper.updateOsstRcpCrYn */
UPDATE  MDS_OSST_ORDER
SET     RCP_CR_YN = 'Y' 
WHERE   OSST_ORDER_SEQ = #{osstOrderSeq}

/* osstMgmtMapper.updateOsstJuoSubInfo */
UPDATE  MSP_JUO_SUB_INFO
SET     SCAN_ID = #{scanId}
WHERE   CONTRACT_NUM = #{contractNum}

